  ('d4f37814-2a55-55e2-8bce-c1d6908b3d7d'::uuid, null, 'enrichissement_web', 'info', 'Adresse exacte du cabinet d''après son site officiel : 15 rue Henri Ribière, 75019 Paris (à Place des Fêtes, comme noté dans le carnet). Le cabinet se trouve sur rue, il ne faut pas entrer dans l''immeuble.'),
  ('4ebc071c-afa2-5304-83b3-37658fe5963d'::uuid, 'annekammerer.sf@gmail.com', null, 'spec', 'Consulte à domicile pour les bébés sur tout Paris.'),
